mapper.select:
SELECT * FROM ( SELECT MSG.CO_ID, MSG.MSG_ID, MSG.ERR_MSG, MSG.ENDPOINT, MSG.RQST_PARA, MSG.MDL_NM, MSG.CRE_USR_ID, MSG.CRE_DT FROM COM_SYS_ERR_MSG MSG WHERE CO_ID = #{coId}
AND MSG.ENDPOINT ILIKE '%' || #{endPoint} || '%'
AND TO_CHAR(MSG.CRE_DT, 'YYYY-MM-DD') BETWEEN #{dateFm} AND #{dateTo}
AND TO_CHAR(MSG.CRE_DT, 'YYYY-MM-DD') BETWEEN TO_CHAR(CURRENT_DATE - INTERVAL '1 day', 'YYYY-MM-DD') AND TO_CHAR(CURRENT_DATE, 'YYYY-MM-DD')
ORDER BY ${sort.sortField} ${sort.sortType}
ORDER BY MSG.CRE_DT DESC
)
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}
